use std::collections::{HashMap, HashSet};

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len() as i64;
    let mut graph = HashMap::new();

    // Build the graph
    for edge in &edges {
        let u = edge[0];
        let v = edge[1];
        let cost = edge[2];
        graph.entry(u).or_insert_with(HashSet::new).insert((v, cost));
    }

    // Use a priority queue to perform a modified Dijkstra's algorithm
    // We prioritize paths with higher minimum edge cost
    use std::collections::BinaryHeap;
    let mut heap = BinaryHeap::new();

    // Start from node 0
    if online[0] {
        heap.push((-1, 0, 0)); // Use negative for max-heap behavior
    }

    let mut max_min_cost = -1;
    let mut visited = HashMap::new();

    while let Some((min_cost, node, total_cost)) = heap.pop() {
        let min_cost = -min_cost;

        // If we've reached the destination
        if node == n - 1 {
            max_min_cost = std::cmp::max(max_min_cost, min_cost);
            continue;
        }

        // Skip if we've already processed this node with a better or equal min cost
        if let Some(&existing_min_cost) = visited.get(&node) {
            if existing_min_cost >= min_cost {
                continue;
            }
        }

        visited.insert(node, min_cost);

        // Explore neighbors
        if let Some(neighbors) = graph.get(&node) {
            for &(v, cost) in neighbors {
                // Skip if the neighbor is offline
                if !online[v as usize] {
                    continue;
                }

                // Check if the total cost exceeds k
                let new_total_cost = total_cost + cost;
                if new_total_cost > k {
                    continue;
                }

                // Update the min cost for this path
                let new_min_cost = std::cmp::min(min_cost, cost);

                // Push to the heap
                heap.push((-new_min_cost, v, new_total_cost));
            }
        }
    }

    max_min_cost
